var e=[{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`......리!`,JPN:`……ベ！`,ENG:`... ri!`,TWN:`……麗！`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_FIRE`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`......이유리!`,JPN:`……カスカベ！`,ENG:`... Lee Yuri!`,TWN:`……李悠麗！`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_FIRE`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`야 임마! 정신 차려!`,JPN:`おい！　しっかりしろ！`,ENG:`Hey! Come on! Get up!`,TWN:`喂！小子！振作點啊！`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_FIRE`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`방금......`,JPN:`うう……`,ENG:`What...`,TWN:`剛才……`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_FIRE`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`대장...... 이게 지금...... 뭐가 어떻게 된 거야?`,JPN:`隊長……これは……どうなってるんだ？`,ENG:`What just... happened, Captain?`,TWN:`隊長……這到底是……怎麼回事？`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_FIRE`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`닥치고 차에 타기나 해!`,JPN:`いいから車に乗れ！`,ENG:`Shut up and just get in the car!`,TWN:`別說了，先上車！`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_FIRE`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`불길이 더 거세지고 있다고.`,JPN:`火の勢いが強くなってきたぞ！`,ENG:`The fire's getting stronger.`,TWN:`火勢越來越猛了。`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_FIRE`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`당장 도망치지 않으면 우리 둘 다 사이 좋게 여기서 타 죽을 거다!`,JPN:`今すぐ逃げないと俺たち二人仲良くここで焼死するぞ！`,ENG:`If we don't get away right now, we'll both become barbecue here!`,TWN:`如果不趕快離開，我們兩個人會被活活燒死！`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_FIRE`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`제길, 시동 좀 걸려!`,JPN:`くそっ、エンジンがかからない！`,ENG:`Dammit, start already!`,TWN:`該死，快動起來！`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_FIRE`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`됐어!`,JPN:`よし！　できた！`,ENG:`There!`,TWN:`好了！`},stage:{bg:`SS_MILITIA_01`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`지금 어디로 가는 거야......? 지훈은?`,JPN:`今どこに向かってるんだ……？　ゴトウは？`,ENG:`Where are we going? And where's Jihoon?`,TWN:`現在要去哪裡……？智勳呢？`},stage:{bg:`SS_MILITIA_01`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`SS_MILITIA_01`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`그런 폭발에 휘말리면, 평범한 사람은 당연히 죽어.`,JPN:`あんな爆発に巻き込まれたら、普通の人間は当然死ぬ。`,ENG:`There's no way any ordinary man could survive a blast like that.`,TWN:`被捲入那麼大的爆炸，普通人肯定會沒命。`},stage:{bg:`SS_MILITIA_01`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`SS_MILITIA_01`,slots:{L:null,C:null,R:null}}},{id:`L25_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`그럼...... 그 자식은? 그 괴물 같은 놈도 죽은 거야?`,JPN:`じゃあ……あいつは？　あの化け物みたいな奴も死んだのか？`,ENG:`Then what about that bastard? Did that monster die too?`,TWN:`那……那傢伙呢？那個怪物也死了嗎？`},stage:{bg:`SS_MILITIA_01`,slots:{L:null,C:null,R:null}}},{id:`L26_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`......몰라. 시체를 확인한 건 아니니까.`,JPN:`……わからない。死体を確かめたわけじゃないからな。`,ENG:`I wouldn't know... I never saw the body.`,TWN:`……不知道，我沒有去確認屍體。`},stage:{bg:`SS_MILITIA_01`,slots:{L:null,C:null,R:null}}},{id:`L27_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`하지만...... 아마도 살아 있겠지.`,JPN:`だが……おそらく生きているだろう。`,ENG:`But... I doubt that he's dead.`,TWN:`不過……可能還活著吧。`},stage:{bg:`SS_MILITIA_01`,slots:{L:null,C:null,R:null}}},{id:`L28_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`카운터란 건, 그런 놈들이니까.`,JPN:`カウンターというのは、そういう存在だから。`,ENG:`It takes a lot to kill a Counter, after all.`,TWN:`所謂制裁者，都是如此。`},stage:{bg:`SS_MILITIA_01`,slots:{L:null,C:null,R:null}}},{id:`L29_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`......제기랄!`,JPN:`……クソ！`,ENG:`Darn it!`,TWN:`可惡！`},stage:{bg:`SS_MILITIA_01`,slots:{L:null,C:null,R:null}}}];export{e as default};